import{_ as r,o as s,c as o,ak as a}from"./chunks/framework.oFDsBAuP.js";const n="/settings/personal/entry-from-dashboard.png",e="/settings/personal/personal-overview.png",i="/settings/personal/personal-account-token.png",l="/settings/personal/personal-change-password.png",g="/settings/personal/2fa-section.png",p="/settings/personal/2fa-qrcode-modal.png",h="/settings/personal/personal-language-preference.png",c="/settings/personal/notification-mail.png",P=JSON.parse('{"title":"个人设置","description":"","frontmatter":{"title":"个人设置"},"headers":[],"relativePath":"settings/user/personal-setting.md","filePath":"settings/user/personal-setting.md"}'),d={name:"settings/user/personal-setting.md"};function m(u,t,_,f,b,k){return s(),o("div",null,[...t[0]||(t[0]=[a('<h2 id="个人设置" tabindex="-1">个人设置 <a class="header-anchor" href="#个人设置" aria-label="Permalink to &quot;个人设置&quot;">​</a></h2><p>在 AtomFlow（原子流动） 控制台管理账号信息、安全选项与第三方绑定。可点击右上角头像选择「<strong>个人设置</strong>」，或进入 <strong>个人中心 → 个人设置</strong>；也可直接访问 <a href="https://atomflow.vip/console/personal" target="_blank" rel="noreferrer">控制台 · 个人设置</a>。</p><h3 id="进入个人设置" tabindex="-1">进入个人设置 <a class="header-anchor" href="#进入个人设置" aria-label="Permalink to &quot;进入个人设置&quot;">​</a></h3><p><img src="'+n+'" alt="从控制台进入个人设置"></p><p>个人设置页分为 <strong>账户管理</strong>、<strong>偏好设置</strong>、<strong>其他设置</strong> 等板块，布局如下。</p><p><img src="'+e+'" alt="个人设置页总览：账户管理、偏好设置与其他设置"></p><h3 id="账户管理" tabindex="-1">账户管理 <a class="header-anchor" href="#账户管理" aria-label="Permalink to &quot;账户管理&quot;">​</a></h3><p>「<strong>账户管理</strong>」包含 <strong>账户绑定</strong> 与 <strong>安全设置</strong> 两个标签：前者用于邮箱、第三方账号与用户名等；后者包含系统访问令牌、密码、Passkey、两步验证与删除账户等。</p><h4 id="账号绑定与系统访问令牌" tabindex="-1">账号绑定与系统访问令牌 <a class="header-anchor" href="#账号绑定与系统访问令牌" aria-label="Permalink to &quot;账号绑定与系统访问令牌&quot;">​</a></h4><ul><li><strong>用户名</strong>：在相应输入框修改后点击「保存」。</li><li><strong>绑定邮箱</strong>：在 <strong>账户绑定</strong> 标签下填写邮箱，点击「发送验证码」，输入验证码完成绑定。</li><li><strong>绑定第三方账号</strong>：在同一标签中选择 GitHub、Discord 等平台，点击「绑定」，在授权页完成流程后返回控制台确认「已绑定」（具体以页面展示为准）。</li></ul><p>在 <strong>安全设置</strong> 标签下可查看 <strong>系统访问令牌</strong>（用于 API 调用的身份凭证）。请妥善保管；若怀疑泄露，可点击「重新生成」。<strong>重新生成后旧令牌立即失效</strong>，依赖旧令牌的集成需同步更新。</p><p><img src="'+i+'" alt="账户管理：安全设置中的系统访问令牌等"></p><p>在 <strong>可用模型</strong>（或同类入口）中可查看当前账号可调用的模型列表，支持搜索与复制模型名称。</p><h4 id="密码管理" tabindex="-1">密码管理 <a class="header-anchor" href="#密码管理" aria-label="Permalink to &quot;密码管理&quot;">​</a></h4><p>在 <strong>安全设置 → 密码管理</strong> 中点击「<strong>修改密码</strong>」，在弹窗中依次填写原密码、新密码与确认新密码，点击「确定」保存。</p><p><img src="'+l+'" alt="修改密码弹窗"></p><h4 id="passkey-登录" tabindex="-1">Passkey 登录 <a class="header-anchor" href="#passkey-登录" aria-label="Permalink to &quot;Passkey 登录&quot;">​</a></h4><ol><li>在 <strong>安全设置</strong> 中找到「<strong>Passkey 登录</strong>」。</li><li>点击「<strong>注册 Passkey</strong>」，按浏览器或系统提示完成验证。</li><li>完成后即可在支持的场景下使用 Passkey 登录。</li></ol><h4 id="两步验证设置" tabindex="-1">两步验证设置 <a class="header-anchor" href="#两步验证设置" aria-label="Permalink to &quot;两步验证设置&quot;">​</a></h4><p>开启两步验证后，登录时除密码外还需输入验证器 App 中的动态码，降低被盗风险。</p><ol><li>在手机上安装验证器 App（推荐 Google Authenticator 或 Microsoft Authenticator）。</li><li>在 <strong>安全设置</strong> 中找到「<strong>两步验证</strong>」，点击「<strong>启用验证</strong>」。</li></ol><p><img src="'+g+'" alt="两步验证：在安全设置中点击启用验证"></p><ol start="3"><li>用验证器扫描页面上的二维码；若无法扫描，可手动输入密钥。</li></ol><p><img src="'+p+'" alt="两步验证：扫描二维码"></p><ol start="4"><li>将验证器中的 6 位动态码填入页面，完成验证。</li><li>按提示保存<strong>备用码</strong>（建议截图或离线保存）；备用码通常只展示一次，丢失且无法使用验证器时需联系管理员处理。</li></ol><h4 id="删除账户" tabindex="-1">删除账户 <a class="header-anchor" href="#删除账户" aria-label="Permalink to &quot;删除账户&quot;">​</a></h4><p>在 <strong>安全设置</strong> 底部的 <strong>删除账户</strong> 为不可逆操作，请谨慎确认后再执行。</p><h3 id="偏好设置" tabindex="-1">偏好设置 <a class="header-anchor" href="#偏好设置" aria-label="Permalink to &quot;偏好设置&quot;">​</a></h3><p>「<strong>偏好设置</strong>」用于界面语言等个人偏好；设置会同步到已登录设备，并可能影响 API 返回错误信息的语言。</p><h4 id="语言偏好" tabindex="-1">语言偏好 <a class="header-anchor" href="#语言偏好" aria-label="Permalink to &quot;语言偏好&quot;">​</a></h4><p>在 <strong>语言偏好</strong> 中选择界面语言（如简体中文），选择后一般会自动保存。</p><p><img src="'+h+'" alt="偏好设置：语言偏好"></p><h3 id="其他设置" tabindex="-1">其他设置 <a class="header-anchor" href="#其他设置" aria-label="Permalink to &quot;其他设置&quot;">​</a></h3><p>「<strong>其他设置</strong>」涵盖通知、边栏等子项，通过顶部标签切换。</p><h4 id="邮件通知" tabindex="-1">邮件通知 <a class="header-anchor" href="#邮件通知" aria-label="Permalink to &quot;邮件通知&quot;">​</a></h4><p>在 <strong>通知配置</strong> 标签中，将通知方式选为「<strong>邮件通知</strong>」，按需填写<strong>额度预警阈值</strong>与<strong>通知邮箱</strong>（留空可使用账号绑定邮箱），点击「<strong>保存设置</strong>」生效。</p><p><img src="'+c+'" alt="其他设置：通知配置（邮件通知）"></p>',37)])])}const x=r(d,[["render",m]]);export{P as __pageData,x as default};
